class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        def manacher_odd(s):
            T = '#'.join('^{}$'.format(s))
            n = len(T)
            P = [0] * n
            C = R = 0
            for i in range(1, n-1):
                P[i] = (R > i) and min(R - i, P[2*C - i]) 
                while T[i + 1 + P[i]] == T[i - 1 - P[i]]:
                    P[i] += 1
                if i + P[i] > R:
                    C, R = i, i + P[i]
            return P
        def manacher_even(s):
            T = '#'.join('^{}$'.format('#' + s + '#'))
            n = len(T)
            P = [0] * n
            C = R = 0
            for i in range(1, n-1):
                P[i] = (R > i) and min(R - i, P[2*C - i]) 
                while T[i + 1 + P[i]] == T[i - 1 - P[i]]:
                    P[i] += 1
                if i + P[i] > R:
                    C, R = i, i + P[i]
            return P
        def manacher(s):
            if len(s) % 2 == 0:
                return manacher_even(s)
            else:
                return manacher_odd(s)
        def get_max_palindrome(s, t):
            max_palindrome = 0
            for i in range(len(s)):
                for j in range(len(t)):
                    palindrome = s[i:i+1] + t[j:j+1]
                    max_palindrome = max(max_palindrome, manacher(palindrome)[-1] // 2)
            return max_palindrome
        return get_max_palindrome(s, t)
